ALTER TABLE experiences ADD COLUMN image1 TEXT NULL AFTER coverImageUrl;
ALTER TABLE experiences ADD COLUMN image2 TEXT NULL AFTER image1;
ALTER TABLE experiences ADD COLUMN image3 TEXT NULL AFTER image2;
ALTER TABLE experiences ADD COLUMN image4 TEXT NULL AFTER image3;

-- Copiar coverImageUrl a image1 para no perder datos existentes
UPDATE experiences SET image1 = coverImageUrl WHERE coverImageUrl IS NOT NULL AND coverImageUrl != '';

