ALTER TABLE categories ADD COLUMN image1 TEXT NULL AFTER imageUrl;

-- Copiar imageUrl a image1
UPDATE categories SET image1 = imageUrl WHERE imageUrl IS NOT NULL AND imageUrl != '';

